//
// KeychainStorage.swift
// RiftSDK
//
// Hand-written Keychain-backed implementation of the `RiftStorage`
// foreign trait generated by UniFFI. Not generated — do not overwrite.
//
// This storage backend persists the Rift SDK's install_id and user
// binding state across app launches AND across app reinstalls (keychain
// entries survive when the app bundle is deleted). This is the key
// reliability win for iOS attribution.
//
// The entries are marked `kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly`
// so they're device-local (never synced to iCloud) and readable as soon
// as the device is unlocked after boot.
//

import Foundation
import Security

public final class KeychainStorage: RiftStorage {
    private let service: String

    /// Create a new Keychain-backed storage.
    ///
    /// - Parameter service: The Keychain `kSecAttrService` value. Defaults to
    ///   `"ink.riftl.sdk"` which is unique to the Rift SDK. Override only if
    ///   you need to isolate multiple Rift SDK instances within the same app.
    public init(service: String = "ink.riftl.sdk") {
        self.service = service
    }

    public func get(key: String) throws -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne,
        ]

        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)

        switch status {
        case errSecSuccess:
            guard
                let data = result as? Data,
                let str = String(data: data, encoding: .utf8)
            else {
                return nil
            }
            return str
        case errSecItemNotFound:
            return nil
        default:
            throw StorageError.IoError(
                message: "keychain read failed (OSStatus \(status))"
            )
        }
    }

    public func set(key: String, value: String) throws {
        guard let data = value.data(using: .utf8) else {
            throw StorageError.IoError(message: "value is not valid UTF-8")
        }

        // Delete any existing entry first — SecItemAdd fails if the item
        // already exists, and SecItemUpdate requires a separate codepath.
        // Deleting+adding is the simplest idempotent overwrite.
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
        ]
        SecItemDelete(query as CFDictionary)

        var add = query
        add[kSecValueData as String] = data
        add[kSecAttrAccessible as String] = kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly

        let status = SecItemAdd(add as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw StorageError.IoError(
                message: "keychain write failed (OSStatus \(status))"
            )
        }
    }

    public func remove(key: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
        ]
        let status = SecItemDelete(query as CFDictionary)

        // errSecItemNotFound is expected when the key wasn't present.
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw StorageError.IoError(
                message: "keychain delete failed (OSStatus \(status))"
            )
        }
    }
}
